from flask import Flask, request, jsonify
import psycopg2
from psycopg2 import sql
import os
from dotenv import load_dotenv

load_dotenv()

app = Flask(__name__)

DATABASE_URL = os.getenv('DATABASE_URL')

def create_connection():
    conn = psycopg2.connect(DATABASE_URL)
    return conn

@app.route('/query', methods=['POST'])
def dynamic_query():
    data = request.json
    table_name = data.get('table')
    columns = data.get('columns', '*')
    filters = data.get('filters', {})

    # Validate table name and columns against a whitelist
    allowed_tables = ['table1', 'table2', 'table3']  # Example allowed tables
    allowed_columns = {
        'table1': ['column1', 'column2'],
        'table2': ['column3', 'column4'],
        'table3': ['column5', 'column6']
    }

    if table_name not in allowed_tables:
        return jsonify({'error': 'Invalid table name'}), 400

    if columns != '*' and any(col not in allowed_columns[table_name] for col in columns.split(',')):
        return jsonify({'error': 'Invalid column name(s)'}), 400

    query = sql.SQL("SELECT {fields} FROM {table}").format(
        fields=sql.SQL(', ').join(map(sql.Identifier, columns.split(','))) if columns != '*' else sql.SQL('*'),
        table=sql.Identifier(table_name)
    )

    if filters:
        filter_clauses = []
        for key, value in filters.items():
            if key not in allowed_columns[table_name]:
                return jsonify({'error': 'Invalid filter column'}), 400
            filter_clauses.append(sql.SQL("{} = %s").format(sql.Identifier(key)))

        query += sql.SQL(" WHERE ") + sql.SQL(" AND ").join(filter_clauses)

    try:
        conn = create_connection()
        with conn.cursor() as cursor:
            cursor.execute(query, list(filters.values()))
            results = cursor.fetchall()
            columns = [desc[0] for desc in cursor.description]
            data = [dict(zip(columns, row)) for row in results]
        return jsonify(data)
    except Exception as e:
        return jsonify({'error': str(e)}), 500
    finally:
        if conn:
            conn.close()

if __name__ == '__main__':
    app.run(debug=False)